import re
import smtplib
from email.mime.text import MIMEText
from typing import List, Optional

EMAIL_RE = re.compile(r'^[^@]+@[^@]+\.[^@]+$')


def validate_email_params(
    to: str, subject: str, cc: Optional[List[str]] = None
) -> None:
    """Validate email parameters. Raises ValueError on invalid input."""
    if not EMAIL_RE.match(to):
        raise ValueError(f"Invalid email: {to}")
    if cc:
        for addr in cc:
            if not EMAIL_RE.match(addr):
                raise ValueError(f"Invalid CC email: {addr}")
    if not subject.strip():
        raise ValueError("Subject cannot be empty")


def compose_message(
    to: str, subject: str, body: str, cc: Optional[List[str]] = None
) -> MIMEText:
    """Compose a MIME email message."""
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['To'] = to
    if cc:
        msg['Cc'] = ', '.join(cc)
    return msg


def deliver_message(
    msg: MIMEText, to: str,
    cc: Optional[List[str]] = None,
    smtp_host: str = "localhost",
) -> bool:
    """Send a composed message via SMTP."""
    try:
        with smtplib.SMTP(smtp_host) as server:
            recipients = [to] + (cc or [])
            server.sendmail(to, recipients, msg.as_string())
        return True
    except smtplib.SMTPException:
        return False


def send_email(
    to: str, subject: str, body: str,
    cc: Optional[List[str]] = None,
    smtp_host: str = "localhost",
) -> bool:
    """Validate, compose, and deliver an email."""
    validate_email_params(to, subject, cc)
    msg = compose_message(to, subject, body, cc)
    return deliver_message(msg, to, cc, smtp_host)
